/**
 * @fileoverview AjaxForm component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, selectors, default config
 *   helpers.js   — FormData conversion, fetch option building, response parsing
 *   state.js     — reactive state wiring
 *   view.js      — DOM setup / teardown + state effects
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/AjaxForm
 */

import { default as razyui } from '../../index.js';

import { DEFAULTS }                                                        from './constants.js';
import { formDataToObject, gatherFormData, buildFetchOpts, parseResponse } from './helpers.js';
import { createReactiveState }                                             from './state.js';
import { wireSubmittingEffect, setupForm, showFieldError, showFormError, clearAllErrors, cleanupDOM } from './view.js';
import { bindEvents }                                                      from './events.js';

/**
 * AjaxForm — v2 modular rewrite
 *
 * Intercepts form submission, sends via fetch (AJAX), handles validation
 * error display, submit locking, and integrates with Dialog for modal forms.
 *
 * Features:
 *   - Intercepts <form> submit → fetch with FormData or JSON
 *   - Submit lock: prevents double-submit, disables button
 *   - Field-level validation errors: inline messages below fields
 *   - Loading state on submit button (spinner + disabled)
 *   - Pluggable response processor
 *   - Reset / clear validation errors
 *   - Reactive state via razyui.state()
 *   - getControl() API: submit(), validate(), reset(), setErrors()
 *   - Dialog integration: works seamlessly inside Dialog.open()
 *
 * Config:
 *   url          — override form action URL
 *   method       — override form method (default from <form> or 'POST')
 *   headers      — extra headers (default: json content-type for JSON mode)
 *   mode         — 'formdata' | 'json' (default 'formdata')
 *   processor    — (response) => { resolve, reject } custom response handler
 *   resetOnSubmit — clear errors before each submit (default true)
 *
 * Callbacks:
 *   onValidation(data, ctrl)    — client-side validation, return false to block
 *   onSuccess(data, response)   — fires on successful submit
 *   onError(errors, response)   — fires on validation errors from server
 *   onComplete(ctrl)            — fires after submit finishes (success or fail)
 *   onSubmit(data, ctrl)        — fires right before fetch, can transform data
 *
 * @param {string|Element} selector — CSS selector or Element for the <form>
 * @param {object} [config]
 */
const AjaxForm = class {
    #form = null;
    #destroyed = false;
    #config = {};
    #stateRef = null;
    #setState = null;
    #fetchAC = null;   // AbortController for in-flight fetch
    #eventAC = null;   // AbortController for event cleanup

    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, method: null, ...config };

        const el = razyui(selector);

        if (!el.length || el[0].tagName !== 'FORM') {
            console.warn('AjaxForm: <form> element not found \u2192', selector);
            return;
        }
        this.#form = el;

        // 1. View — add base class
        setupForm(el);

        // 2. State — reactive state + submitting effect
        const { ref, setState, stateSet } = createReactiveState(razyui.state);
        this.#stateRef = ref;
        this.#setState = setState;
        wireSubmittingEffect(stateSet, el);

        // 3. Events — bind with AbortController cleanup
        this.#eventAC = bindEvents(el, {
            onSubmit: () => this.#handleSubmit(),
        });
    }

    // ────────────────────────────────────────────
    // Submit
    // ────────────────────────────────────────────

    async #handleSubmit() {
        if (this.#stateRef.submitting) return;

        const cfg  = this.#config;
        const form = this.#form;

        // Reset errors
        if (cfg.resetOnSubmit !== false) {
            this.clearErrors();
        }

        // Gather data
        let data = gatherFormData(form, cfg.mode);

        // Client-side validation
        if (typeof cfg.onValidation === 'function') {
            const ctrl = this.getControl();
            const result = await cfg.onValidation(data, ctrl);
            if (result === false) return;
        }

        // Transform data
        if (typeof cfg.onSubmit === 'function') {
            const transformed = cfg.onSubmit(data, this.getControl());
            if (transformed !== undefined) data = transformed;
        }

        // Submit
        const url    = cfg.url || form.action || '';
        const method = (cfg.method || form.method || DEFAULTS.method).toUpperCase();

        // Cancel previous
        this.#fetchAC?.abort();
        this.#fetchAC = new AbortController();

        this.#setState({ submitting: true });

        try {
            let result, response;

            if (typeof url === 'function') {
                // Function URL — call directly, skip fetch
                result   = await url(data, method);
                response = { ok: true, status: 200 };
            } else {
                const fetchOpts = buildFetchOpts(method, data, cfg.mode, cfg.headers, this.#fetchAC.signal);
                response = await fetch(url, fetchOpts);
                result   = await parseResponse(response);
            }

            // Custom processor
            if (typeof cfg.processor === 'function') {
                await new Promise((resolve, reject) => {
                    cfg.processor.call({
                        resolve: (data, raw) => {
                            if (typeof cfg.onSuccess === 'function') {
                                cfg.onSuccess.call(this, data, raw);
                            }
                            resolve(data);
                        },
                        reject: (errors, raw) => {
                            if (typeof cfg.onError === 'function') {
                                cfg.onError.call(this, errors, raw);
                            }
                            if (razyui.isPO(errors)) {
                                this.setErrors(errors);
                            }
                            reject(errors);
                        },
                    }, result, response);
                });
            } else {
                // Default handling
                if (response.ok) {
                    if (typeof cfg.onSuccess === 'function') {
                        cfg.onSuccess.call(this, result, response);
                    }
                } else {
                    // Try to extract field errors from response
                    if (razyui.isPO(result)) {
                        const errors = result.errors || result.response || result;
                        if (typeof cfg.onError === 'function') {
                            cfg.onError.call(this, errors, response);
                        }
                        this.setErrors(errors);
                    } else {
                        if (typeof cfg.onError === 'function') {
                            cfg.onError.call(this, result, response);
                        }
                    }
                }
            }
        } catch (err) {
            if (err.name !== 'AbortError') {
                if (typeof cfg.onError === 'function') {
                    cfg.onError.call(this, err, null);
                }
            }
        } finally {
            this.#setState({ submitting: false });

            if (typeof cfg.onComplete === 'function') {
                cfg.onComplete(this.getControl());
            }
        }
    }

    // ────────────────────────────────────────────
    // Validation error display
    // ────────────────────────────────────────────

    /**
     * Set field-level errors.
     * @param {object|string} errors — { fieldName: "message" } or a single string for form-level
     */
    setErrors(errors) {
        if (typeof errors === 'string') {
            showFormError(this.#form, errors);
            return;
        }

        if (typeof errors !== 'object' || errors === null) return;

        for (const [name, message] of Object.entries(errors)) {
            const msg = Array.isArray(message) ? message[0] : message;
            showFieldError(this.#form, name, msg);
        }
    }

    /**
     * Clear all validation errors.
     */
    clearErrors() {
        clearAllErrors(this.#form);
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    getControl() {
        const self = this;
        return {
            /** Programmatically trigger submit */
            submit: () => { self.#handleSubmit(); },

            /** Set validation errors */
            setErrors: (errors) => { self.setErrors(errors); },

            /** Clear all errors */
            clearErrors: () => { self.clearErrors(); },

            /** Reset form to initial values + clear errors */
            reset: () => {
                self.#form[0].reset();
                self.clearErrors();
            },

            /** Get current submitting state */
            get submitting() { return self.#stateRef.submitting; },
            /** Alias for submitting — loading state */
            get loading() { return self.#stateRef.submitting; },

            /** Get the form element */
            get form() { return self.#form; },

            /** Get form data as object */
            getData: () => {
                return formDataToObject(self.#form.getFormData());
            },
            destroy: () => self.destroy(),
            get element() { return self.#form[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#fetchAC?.abort();
        this.#eventAC?.abort();
        cleanupDOM(this.#form);
    }
};

// ────────────────────────────────────────────
// Static helper: wrap any form
// ────────────────────────────────────────────

/**
 * Auto-wrap all forms matching a selector.
 * @param {string} selector
 * @param {object} config
 * @returns {AjaxForm[]}
 */
AjaxForm.wrapAll = function (selector, config = {}) {
    return razyui(selector).map(
        form => new AjaxForm(form, config)
    );
};

export default AjaxForm;
