/**
 * @fileoverview AjaxForm barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/AjaxForm
 */
import { default as razyui } from '../index.js';
import { AjaxFormDef as DEF } from './AjaxForm.def.js';
import AjaxForm from './AjaxForm/index.js';

// ── Module registration ──
razyui.AjaxForm = AjaxForm;

// ── JIT Component Definition registration ──
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

/**
 * Registers the custom element for the AjaxForm component.
 * Defines the custom element using the tag and observed attributes from the component definition.
 * 
 * @function registerElement
 * @returns {void}
 */
export function registerElement() {
    const { tag, observedAttrs, attrMap } = DEF.ce;
    
    // Prevent duplicate registration
    if (customElements.get(tag)) return;
    
    // Define the custom element
    customElements.define(tag, class extends HTMLElement {
        /**
         * Returns the list of attributes to observe for changes.
         * 
         * @returns {string[]} Array of observed attribute names.
         */
        static get observedAttributes() { return observedAttrs; }
        
        /**
         * Called when the element is inserted into the DOM.
         * Initializes the AjaxForm controller.
         */
        connectedCallback()    { this._ctrl = new AjaxForm(this, this.dataset); }
        
        /**
         * Called when the element is removed from the DOM.
         * Destroys the AjaxForm controller to free up resources.
         */
        disconnectedCallback() { this._ctrl?.destroy?.(); }
        
        /**
         * Called when an observed attribute is changed.
         * Updates the corresponding property on the AjaxForm controller.
         * 
         * @param {string} n - The name of the attribute that changed.
         * @param {string} o - The old value of the attribute.
         * @param {string} v - The new value of the attribute.
         */
        attributeChangedCallback(n, o, v) {
            if (o !== v && this._ctrl) this._ctrl[attrMap[n]] = v;
        }
        
        /**
         * Gets the AjaxForm controller instance associated with this element.
         * 
         * @returns {AjaxForm} The AjaxForm controller instance.
         */
        get control() { return this._ctrl; }
    });
}

export default AjaxForm;
export const stylesheet = null;
