/**
 * @fileoverview AjaxForm helpers — pure utility functions (no DOM, no `this`).
 * @module module/AjaxForm/helpers
 */

/**
 * Convert FormData to a plain object, handling array fields (name="foo[]").
 *
 * @param {FormData} formData
 * @returns {object}
 */
export function formDataToObject(formData) {
    const data = {};
    formData.forEach((val, key) => {
        if (key.endsWith('[]')) {
            const k = key.slice(0, -2);
            if (!data[k]) data[k] = [];
            data[k].push(val);
        } else {
            data[key] = val;
        }
    });
    return data;
}

/**
 * Gather form data, optionally converting to plain object for JSON mode.
 *
 * @param {HTMLFormElement} form
 * @param {'formdata'|'json'} mode
 * @returns {FormData|object}
 */
export function gatherFormData(form, mode) {
    const formData = form.getFormData();
    return mode === 'json' ? formDataToObject(formData) : formData;
}

/**
 * Build fetch RequestInit options for the given method, data, mode, and headers.
 *
 * @param {string} method — HTTP method (uppercased)
 * @param {FormData|object} data — request body payload
 * @param {'formdata'|'json'} mode — serialisation mode
 * @param {object} [headers] — extra headers from config
 * @param {AbortSignal} signal — abort signal for cancellation
 * @returns {RequestInit}
 */
export function buildFetchOpts(method, data, mode, headers, signal) {
    const opts = { method, signal };

    if (method !== 'GET' && method !== 'HEAD') {
        if (mode === 'json') {
            opts.headers = Object.assign(
                { 'Content-Type': 'application/json' },
                headers || {}
            );
            opts.body = JSON.stringify(data);
        } else {
            opts.body = data;
            if (headers) opts.headers = headers;
        }
    }

    return opts;
}

/**
 * Parse a fetch Response based on its Content-Type header.
 *
 * @param {Response} response
 * @returns {Promise<any>}
 */
export async function parseResponse(response) {
    const contentType = response.headers.get('content-type') || '';
    return contentType.includes('application/json')
        ? response.json()
        : response.text();
}
