/**
 * @fileoverview AjaxForm constants — CSS classes, selectors, default config.
 * @module module/AjaxForm/constants
 */
import { defineParts } from '../shared/definePart.js';


/** CSS class names */
export const CLS = Object.freeze({
    FORM:       'af-form',
    FIELD:      'af-field',
    ERROR:      'form-error',
    FORM_ERROR: 'form-error-banner',
    HAS_ERROR:  'has-error',
    SUBMITTING: 'is-submitting',
});

/** DOM selectors */
export const SEL = Object.freeze({
    SUBMIT_BTN: '[type="submit"], button:not([type])',
    HAS_ERROR:  '.has-error',
    ERRORS:     '.form-error, .form-error-banner',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    method:          'POST',
    mode:            'formdata',
    resetOnSubmit: true,
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('AjaxForm', {
    FORM        : { class: 'af-form', aliases: ['form', 'root'] },
});

PART.FORM.jit     = [
'relative {is-submitting}:pointer-events-none',
'[&_input]:{is-submitting}:[opacity:0.6] [&_select]:{is-submitting}:[opacity:0.6] [&_textarea]:{is-submitting}:[opacity:0.6]',
'[&_.has-error_input]:[border-color:var(--rui-danger)] [&_.has-error_select]:[border-color:var(--rui-danger)] [&_.has-error_textarea]:[border-color:var(--rui-danger)]',
'[&_.has-error_input]:focus:[box-shadow:0_0_0_3px_var(--rui-danger-subtle)] [&_.has-error_select]:focus:[box-shadow:0_0_0_3px_var(--rui-danger-subtle)] [&_.has-error_textarea]:focus:[box-shadow:0_0_0_3px_var(--rui-danger-subtle)]',
].join(' ');