/**
 * @fileoverview AjaxForm view — DOM setup / teardown + reactive state effects.
 * @module module/AjaxForm/view
 */

import razyui from '../../index.js';
import { CLS, SEL, PART } from './constants.js';

// ═══════════════════════════════════════
//  Reactive State Effects
// ═══════════════════════════════════════

/**
 * Apply the submitting visual state to the form.
 * Toggles the `is-submitting` class and disables submit buttons.
 *
 * @param {HTMLFormElement} form
 * @param {boolean} submitting
 */
export function applySubmittingState(form, submitting) {
    form.toggleClass(CLS.SUBMITTING, !!submitting);
    form[0].setAttribute('aria-busy', String(!!submitting));

    const btns = form.find(SEL.SUBMIT_BTN);
    btns.forEach(b => {
        b.disabled = !!submitting;
    });
}

/**
 * Wire the reactive state effect so DOM updates whenever `submitting` changes.
 *
 * @param {object} stateSet — value returned by `razyui.state()`
 * @param {HTMLFormElement} form
 */
export function wireSubmittingEffect(stateSet, form) {
    stateSet.effect(function () {
        applySubmittingState(form, this.submitting);
    });
}

// ═══════════════════════════════════════
//  DOM Setup
// ═══════════════════════════════════════

/**
 * Add the base form class.
 *
 * @param {HTMLFormElement} form
 */
export function setupForm(form) {
    form.addClass('ajax-form ' + CLS.FORM);
    PART.FORM.apply(form);
}

// ═══════════════════════════════════════
//  Error Display
// ═══════════════════════════════════════

/**
 * Show an inline error message below a named field.
 *
 * @param {HTMLFormElement} form
 * @param {string} name — field `name` attribute value
 * @param {string} message
 */
export function showFieldError(form, name, message) {
    const input = form.find(`[name="${name}"], [name="${name}[]"]`);
    if (!input.length) return;

    const wrapper = input.closest('.' + CLS.FIELD);
    const field = wrapper.length ? wrapper : input.parent();
    if (!field.length) return;

    field.addClass(CLS.HAS_ERROR);

    // Remove existing error message
    const existing = field.find('.' + CLS.ERROR);
    if (existing.length) existing.remove();

    const errEl = razyui.el('div', { className: CLS.ERROR, textContent: message });
    field.append(errEl);

    // Scroll first error into view
    if (!form.find('.' + CLS.HAS_ERROR + ':not(:first-of-type)')) {
        input[0].focus();
    }
}

/**
 * Show a form-level error at the top of the form.
 *
 * @param {HTMLFormElement} form
 * @param {string} message
 */
export function showFormError(form, message) {
    // Remove existing
    const existing = form.find('.' + CLS.FORM_ERROR);
    if (existing.length) existing.remove();

    const errEl = razyui.el('div', { className: CLS.FORM_ERROR, textContent: message });
    form.prepend(errEl);
}

/**
 * Clear the error state from a single field container.
 *
 * @param {HTMLElement} field — `.af-field` element
 */
export function clearFieldError(field) {
    field.removeClass(CLS.HAS_ERROR);
    const err = field.find('.' + CLS.ERROR);
    if (err.length) err.detach();
}

/**
 * Clear all validation errors (field-level and form-level).
 *
 * @param {HTMLFormElement} form
 */
export function clearAllErrors(form) {
    form.find('.' + CLS.HAS_ERROR).removeClass(CLS.HAS_ERROR).find(SEL.ERRORS).forEach(e => e.remove());
}

// ═══════════════════════════════════════
//  DOM Teardown
// ═══════════════════════════════════════

/**
 * Remove all classes and error elements added by AjaxForm.
 *
 * @param {HTMLFormElement} form
 */
export function cleanupDOM(form) {
    form.removeClass(CLS.FORM, CLS.SUBMITTING);
    PART.FORM.unapply(form);
    clearAllErrors(form);
}
