/**
 * @fileoverview AjaxForm state — reactive state wiring.
 *
 * No state machine transitions (AjaxForm uses a single boolean flag).
 * Provides the reactive `submitting` state used by the orchestrator.
 *
 * @module module/AjaxForm/state
 */

/**
 * Create the reactive AjaxForm state.
 *
 * @param {Function} stateFn — `razyui.state` factory
 * @returns {{ ref: object, setState: Function, stateSet: object }}
 */
export function createReactiveState(stateFn) {
    const stateSet = stateFn({ submitting: false });
    const ref      = stateSet[0];
    const setState = stateSet[1];

    return { ref, setState, stateSet };
}
