/**
 * @fileoverview AjaxForm events — centralised event binding via AbortController.
 * @module module/AjaxForm/events
 */

import razyui from '../../index.js';
import { CLS } from './constants.js';
import { clearFieldError } from './view.js';

/**
 * Bind form submit and input events.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {HTMLFormElement} form — event delegation root
 * @param {{ onSubmit: Function }} handlers — handler callbacks
 * @returns {AbortController}
 */
export function bindEvents(form, handlers) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    const $form = razyui(form);

    $form.on('submit', (e) => {
        e.preventDefault();
        handlers.onSubmit();
    }, opts);

    // Clear field error on input
    $form.on('input', (e) => {
        const field = razyui(e.target).closest('.' + CLS.FIELD);
        if (field.hasClass(CLS.HAS_ERROR)) {
            clearFieldError(field);
        }
    }, opts);

    return ac;
}
